    syncActiveFrameSettingsUI();
    updatePixfindModeUI();
    updateExportOriginalToggleUI();
    syncTimelapseControls();
    updateMirrorGuideHandles();
    updateCanvasResizeHandlePosition();
    syncCanvasResizeHandleVisibility();
    syncMultiControls();
    applyMultiRoleUiLocks();
