  function queueUpdateHistoryAdRender() {
    if (window.__PIXIEED_ADS_DISABLED__ || window.pixieedAdFree?.state?.isActive) {
      return;
    }
    const dialog = dom.updateHistory?.dialog;
    const adSlot = dom.updateHistory?.adSlot;
    if (!(dialog instanceof HTMLDialogElement) || !dialog.open || !(adSlot instanceof HTMLElement)) {
      return;
    }
    if (updateHistoryAdRequested) {
      return;
    }
    if (adSlot.dataset.loaded === '1' || adSlot.getAttribute('data-adsbygoogle-status') === 'done') {
      updateHistoryAdRequested = true;
      return;
    }
    if (!adSlot.classList.contains('adsbygoogle')) {
      adSlot.classList.add('adsbygoogle');
    }

    const getWidth = () => {
      try {
        const rect = adSlot.getBoundingClientRect();
        return (rect && rect.width) || adSlot.clientWidth || adSlot.offsetWidth || 0;
      } catch (error) {
        return adSlot.clientWidth || adSlot.offsetWidth || 0;
      }
    };

    let attempts = 0;
    const MAX_ATTEMPTS = 24;
    const renderWhenReady = () => {
      if (!(dialog instanceof HTMLDialogElement) || !dialog.open) {
        updateHistoryAdRequested = false;
        return;
      }
      const width = getWidth();
      if (width <= 0) {
        attempts += 1;
        if (attempts < MAX_ATTEMPTS) {
          window.requestAnimationFrame(renderWhenReady);
          return;
        }
        updateHistoryAdRequested = false;
        return;
      }
      updateHistoryAdRequested = true;
      try {
        (window.adsbygoogle = window.adsbygoogle || []).push({});
        adSlot.dataset.loaded = '1';
      } catch (error) {
        updateHistoryAdRequested = false;
      }
    };

    window.requestAnimationFrame(renderWhenReady);
  }

  function parseUpdateHistoryTimestamp(value) {
    const timestamp = Date.parse(value);
    return Number.isFinite(timestamp) ? timestamp : 0;
  }

  function normalizeUpdateHistoryEntry(entry) {
    if (!entry || typeof entry !== 'object') {
      return null;
    }
    const at = typeof entry.at === 'string' ? entry.at : '';
    const timestamp = parseUpdateHistoryTimestamp(at);
    if (!timestamp) {
      return null;
    }
    const title = typeof entry.title === 'string' ? entry.title.trim() : '';
    if (!title) {
      return null;
    }
    const detailsSource = Array.isArray(entry.details) ? entry.details : [];
    const details = detailsSource
      .map(detail => (typeof detail === 'string' ? detail.trim() : ''))
      .filter(Boolean);
    const idSource = typeof entry.id === 'string' ? entry.id.trim() : '';
    const id = idSource || `${at}:${title}`;
    return {
      id,
      at,
      timestamp,
      title,
      details,
    };
  }

  function loadStoredUpdateHistoryEntries() {
    if (!canUseSessionStorage) {
      return [];
    }
    try {
      const raw = window.localStorage.getItem(UPDATE_HISTORY_STORAGE_KEY);
      if (!raw) {
        return [];
      }
      const parsed = JSON.parse(raw);
      if (!Array.isArray(parsed)) {
        return [];
      }
      return parsed;
    } catch (error) {
      return [];
    }
  }

  function saveStoredUpdateHistoryEntries(entries) {
    if (!canUseSessionStorage) {
      return;
    }
    try {
      const payload = Array.isArray(entries)
        ? entries.map(entry => ({
          id: entry.id,
          at: entry.at,
          title: entry.title,
          details: Array.isArray(entry.details) ? entry.details : [],
        }))
        : [];
      window.localStorage.setItem(UPDATE_HISTORY_STORAGE_KEY, JSON.stringify(payload));
    } catch (error) {
      // Ignore localStorage errors.
    }
  }

  function getUpdateHistoryEntries() {
    const cutoff = Date.now() - UPDATE_HISTORY_RETENTION_MS;
    const mergedById = new Map();
    const source = [
      ...loadStoredUpdateHistoryEntries(),
      ...BUILTIN_UPDATE_HISTORY_ENTRIES,
    ];
    source.forEach(entry => {
      if (!entry || typeof entry !== 'object') {
        return;
      }
      const entryId = typeof entry.id === 'string' ? entry.id.trim() : '';
      if ((entry.published === false) || (entryId && SUPPRESSED_UPDATE_HISTORY_IDS.has(entryId))) {
        return;
      }
      const normalized = normalizeUpdateHistoryEntry(entry);
      if (!normalized) {
        return;
      }
      if (normalized.timestamp < cutoff) {
        return;
      }
      const previous = mergedById.get(normalized.id);
      if (!previous || normalized.timestamp >= previous.timestamp) {
        mergedById.set(normalized.id, normalized);
      }
    });
    const merged = Array.from(mergedById.values()).sort((a, b) => b.timestamp - a.timestamp);
    saveStoredUpdateHistoryEntries(merged);
    return merged;
  }

  function formatUpdateHistoryDate(timestamp, fallback = '') {
    if (!Number.isFinite(timestamp) || timestamp <= 0) {
      return fallback;
    }
    const d = new Date(timestamp);
    const y = d.getFullYear();
    const m = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    const hh = String(d.getHours()).padStart(2, '0');
    const mm = String(d.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${day} ${hh}:${mm}`;
  }

  function renderUpdateHistoryPanel() {
    const list = dom.updateHistory?.list;
    if (!(list instanceof HTMLElement)) {
      return;
    }
    list.replaceChildren();
    const entries = getUpdateHistoryEntries();
    if (!entries.length) {
      const empty = document.createElement('p');
      empty.className = 'help-text';
      empty.textContent = '更新履歴は準備中です。';
      list.appendChild(empty);
      return;
    }
    entries.forEach(entry => {
      const item = document.createElement('article');
      item.className = 'update-history-item';
      item.setAttribute('role', 'listitem');
      const head = document.createElement('div');
      head.className = 'update-history-item__head';
      const title = document.createElement('h3');
      title.className = 'update-history-item__title';
      title.textContent = entry.title;
      const time = document.createElement('time');
      time.className = 'update-history-item__time';
      time.dateTime = entry.at;
      time.textContent = formatUpdateHistoryDate(entry.timestamp, entry.at);
      head.append(title, time);
      item.appendChild(head);
      if (entry.details.length) {
        const detailList = document.createElement('ul');
        detailList.className = 'update-history-item__details';
        entry.details.forEach(detail => {
          const row = document.createElement('li');
          row.textContent = detail;
          detailList.appendChild(row);
        });
        item.appendChild(detailList);
      }
      list.appendChild(item);
    });
  }

  function openUpdateHistoryDialog() {
    const dialog = dom.updateHistory?.dialog;
    if (!(dialog instanceof HTMLDialogElement) || typeof dialog.showModal !== 'function') {
      return;
    }
    renderUpdateHistoryPanel();
    if (dialog.open) {
      return;
    }
    dialog.showModal();
    window.requestAnimationFrame(() => {
      queueUpdateHistoryAdRender();
      dom.updateHistory?.close?.focus?.({ preventScroll: true });
    });
  }

  function closeUpdateHistoryDialog() {
    const dialog = dom.updateHistory?.dialog;
    if (dialog instanceof HTMLDialogElement && dialog.open) {
      dialog.close();
    }
  }

  function setupUpdateHistoryDialog() {
    const dialog = dom.updateHistory?.dialog;
    if (!(dialog instanceof HTMLDialogElement) || typeof dialog.showModal !== 'function') {
      if (dialog) {
        dialog.hidden = true;
      }
      return;
    }
    dom.updateHistory?.close?.addEventListener('click', () => {
      closeUpdateHistoryDialog();
    });
    dialog.addEventListener('cancel', event => {
      event.preventDefault();
      closeUpdateHistoryDialog();
    });
  }

  function shuffleToolSpotlightCards() {
    const list = dom.toolSpotlight?.list;
    if (!(list instanceof HTMLElement)) {
      return;
    }
    const cards = Array.from(list.querySelectorAll('.tool-spotlight-card'));
    if (cards.length <= 1) {
      return;
    }
    const visibleCards = cards.filter(card => !(card.hidden || card.getAttribute('aria-hidden') === 'true'));
    if (visibleCards.length <= 1) {
      return;
    }
    const tipCard = dom.toolSpotlight?.supportTip || null;
    const contestTitle = document.getElementById('toolSpotlightContestTitle');
    const contestCard = contestTitle instanceof HTMLElement
      ? contestTitle.closest('.tool-spotlight-card')
      : null;
    const shuffled = visibleCards.filter(card => card !== tipCard && card !== contestCard);
    if (shuffled.length > 1) {
      for (let i = shuffled.length - 1; i > 0; i -= 1) {
        const j = Math.floor(Math.random() * (i + 1));
        [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
      }
    }
    if (tipCard && !(tipCard.hidden || tipCard.getAttribute('aria-hidden') === 'true')) {
      list.appendChild(tipCard);
    }
    shuffled.forEach(card => list.appendChild(card));
    if (contestCard && !(contestCard.hidden || contestCard.getAttribute('aria-hidden') === 'true')) {
      list.appendChild(contestCard);
    }
    const visibleSet = new Set([tipCard, contestCard, ...shuffled].filter(Boolean));
    cards.forEach(card => {
      if (!visibleSet.has(card)) {
        list.appendChild(card);
      }
    });
  }

  function openToolSpotlightDialog() {
    const dialog = dom.toolSpotlight?.dialog;
    if (!(dialog instanceof HTMLDialogElement) || typeof dialog.showModal !== 'function') {
      return;
    }
    if (dialog.open) {
      return;
    }
    shuffleToolSpotlightCards();
    dialog.showModal();
    window.requestAnimationFrame(() => {
      dom.toolSpotlight?.close?.focus?.({ preventScroll: true });
    });
  }

  function closeToolSpotlightDialog() {
    const dialog = dom.toolSpotlight?.dialog;
    if (dialog instanceof HTMLDialogElement && dialog.open) {
      dialog.close();
    }
  }

  function openLoginPromptDialog() {
    if (accountState.isLoggedIn) {
      return;
    }
    const dialog = dom.loginPrompt?.dialog;
    if (!(dialog instanceof HTMLDialogElement) || typeof dialog.showModal !== 'function') {
      return;
    }
    if (dialog.open) {
      return;
    }
    dialog.showModal();
    window.requestAnimationFrame(() => {
      dom.loginPrompt?.close?.focus?.({ preventScroll: true });
    });
  }

  function closeLoginPromptDialog() {
    const dialog = dom.loginPrompt?.dialog;
    if (dialog instanceof HTMLDialogElement && dialog.open) {
      dialog.close();
    }
  }

  function showLoginPromptAfterExport() {
    openToolSpotlightDialog();
    if (accountState.isLoggedIn) {
      return;
    }
    const spotlightDialog = dom.toolSpotlight?.dialog;
    if (spotlightDialog instanceof HTMLDialogElement && spotlightDialog.open) {
      spotlightDialog.addEventListener('close', () => {
        openLoginPromptDialog();
      }, { once: true });
      return;
    }
    openLoginPromptDialog();
  }

  function canShowExportInterstitial() {
    if (window.__PIXIEED_ADS_DISABLED__ || window.pixieedAdFree?.state?.isActive) {
      return false;
    }
    const dialog = dom.exportInterstitial?.dialog;
    if (!(dialog instanceof HTMLDialogElement) || typeof dialog.showModal !== 'function') {
      return false;
    }
    if (!canUseSessionStorage) {
      return true;
    }
    try {
      const lastShownAt = Number(window.localStorage.getItem(EXPORT_INTERSTITIAL_LAST_SHOWN_KEY) || 0);
      if (!Number.isFinite(lastShownAt) || lastShownAt <= 0) {
        return true;
      }
      return Date.now() - lastShownAt >= EXPORT_INTERSTITIAL_COOLDOWN_MS;
    } catch (error) {
      return true;
    }
  }

  function markExportInterstitialShown() {
    if (!canUseSessionStorage) {
      return;
    }
    try {
      window.localStorage.setItem(EXPORT_INTERSTITIAL_LAST_SHOWN_KEY, String(Date.now()));
    } catch (error) {
      // Ignore localStorage errors.
    }
  }

  function queueExportInterstitialAdRender() {
    if (window.__PIXIEED_ADS_DISABLED__ || window.pixieedAdFree?.state?.isActive) {
      return;
    }
    const dialog = dom.exportInterstitial?.dialog;
    const adSlot = dom.exportInterstitial?.adSlot;
    if (!(dialog instanceof HTMLDialogElement) || !dialog.open || !(adSlot instanceof HTMLElement)) {
      return;
    }
    if (exportInterstitialAdRequested) {
      return;
    }
    if (adSlot.dataset.loaded === '1' || adSlot.getAttribute('data-adsbygoogle-status') === 'done') {
      exportInterstitialAdRequested = true;
      return;
    }
    if (!adSlot.classList.contains('adsbygoogle')) {
      adSlot.classList.add('adsbygoogle');
    }

    const getWidth = () => {
      try {
        const rect = adSlot.getBoundingClientRect();
        return (rect && rect.width) || adSlot.clientWidth || adSlot.offsetWidth || 0;
      } catch (error) {
        return adSlot.clientWidth || adSlot.offsetWidth || 0;
      }
    };

    let attempts = 0;
    const MAX_ATTEMPTS = 36;
    const renderWhenReady = () => {
      if (!(dialog instanceof HTMLDialogElement) || !dialog.open) {
        exportInterstitialAdRequested = false;
        return;
      }
      const width = getWidth();
      if (width <= 0) {
        attempts += 1;
        if (attempts < MAX_ATTEMPTS) {
          window.requestAnimationFrame(renderWhenReady);
          return;
        }
        exportInterstitialAdRequested = false;
        return;
      }
      exportInterstitialAdRequested = true;
      try {
        (window.adsbygoogle = window.adsbygoogle || []).push({});
        adSlot.dataset.loaded = '1';
      } catch (error) {
        exportInterstitialAdRequested = false;
      }
    };

    window.requestAnimationFrame(renderWhenReady);
  }

  function runPendingExportAction() {
    const action = pendingExportAction;
    pendingExportAction = null;
    if (typeof action !== 'function') {
      return;
    }
    try {
      const result = action();
      if (result && typeof result.then === 'function') {
        result.catch(error => {
          console.warn('Export action failed', error);
        });
      }
    } catch (error) {
      console.warn('Export action failed', error);
    }
  }

  function closeExportInterstitial({ runPendingExport = false } = {}) {
    const dialog = dom.exportInterstitial?.dialog;
    if (!(dialog instanceof HTMLDialogElement)) {
      return;
    }
    const wasOpen = dialog.open;
    if (wasOpen) {
      dialog.close();
    }
    exportInterstitialAdRequested = false;
    document.body.classList.remove('is-export-interstitial-active');
    if (runPendingExport && wasOpen) {
      window.requestAnimationFrame(() => {
        runPendingExportAction();
      });
    }
  }

  function queueExportWithInterstitial(action) {
    if (typeof action !== 'function') {
      return;
    }
    pendingExportAction = action;
    const opened = openExportInterstitialDialog({ force: true });
    if (!opened) {
      runPendingExportAction();
    }
  }

  function setupTopActionButtons() {
    dom.topActionButtons = Array.from(document.querySelectorAll('[data-ui-action]'));
    if (!Array.isArray(dom.topActionButtons) || !dom.topActionButtons.length) {
      return;
    }
    syncExternalToolActionButtons();
    dom.topActionButtons.forEach(button => {
      if (!(button instanceof HTMLButtonElement) || button.dataset.actionBound === 'true') {
        return;
      }
      button.dataset.actionBound = 'true';
      button.addEventListener('click', () => {
        const action = button.dataset.uiAction || '';
        if (!action) {
          return;
        }
        runUiAction(action, { sourceButton: button });
      });
    });
  }

  function openExportInterstitialDialog({ force = false } = {}) {
    const dialog = dom.exportInterstitial?.dialog;
    if (!(dialog instanceof HTMLDialogElement) || typeof dialog.showModal !== 'function') {
      return false;
    }
    if (dialog.open) {
      return true;
    }
    if (!force && !canShowExportInterstitial()) {
      return false;
    }
    markExportInterstitialShown();
    dialog.showModal();
    document.body.classList.add('is-export-interstitial-active');
    queueExportInterstitialAdRender();
    window.requestAnimationFrame(() => {
      dom.exportInterstitial?.close?.focus?.({ preventScroll: true });
    });
    return true;
  }

  function exportProjectWithFallback() {
    if (!ensureCurrentClientCanExportProject({ announce: true })) {
      return;
    }
    const choice = window.prompt(
      '出力形式を入力してください (png / jpeg / svg / glb / grid / gif / timelapse / pixfind / project)',
      'png'
    );
    if (!choice) {
      return;
    }
    const inputMode = choice.trim().toLowerCase();
    if (inputMode === 'contest') {
      updateAutosaveStatus('コンテスト投稿は現在停止中です', 'warn');
      return;
    }
    if (
      inputMode !== 'png'
      && inputMode !== 'jpg'
      && inputMode !== 'jpeg'
      && inputMode !== 'svg'
      && inputMode !== 'glb'
      && inputMode !== 'grid'
      && inputMode !== 'gridpng'
      && inputMode !== 'spritemap'
      && inputMode !== 'spritesheet'
      && inputMode !== 'gif'
      && inputMode !== 'timelapse'
      && inputMode !== 'pixfind'
      && inputMode !== 'project'
    ) {
      window.alert('png / jpeg / svg / glb / spritemap / grid / gif / timelapse / pixfind / project のいずれかを入力してください。');
      return;
    }
    const normalized = normalizeExportFormat(inputMode);
    if (!ensureCurrentClientCanExportProject({ announce: true, format: normalized })) {
      return;
    }
    queueExportWithInterstitial(() => performExportByMode(normalized));
  }

  async function performExportByMode(mode) {
    const normalized = normalizeExportFormat(mode || 'png');
    if (normalized === 'gif') {
      await exportProjectAsGif();
    } else if (normalized === 'jpeg') {
      await exportProjectAsJpeg();
    } else if (normalized === 'svg') {
      await exportProjectAsSvg();
    } else if (normalized === 'spritemap') {
      await exportProjectAsSpriteMap();
    } else if (normalized === 'glb') {
      await exportProjectAsGlb();
    } else if (normalized === 'gridpng') {
      await exportProjectAsGridPng();
    } else if (normalized === 'timelapse') {
      await exportTimelapseGif();
    } else if (normalized === 'contest') {
      updateAutosaveStatus('コンテスト投稿は現在停止中です', 'warn');
    } else if (normalized === 'pixfind') {
      exportProjectToPixfind();
    } else if (normalized === 'project') {
      const result = await saveProjectAsPixieedraw();
      if (result?.saved) {
        showLoginPromptAfterExport();
      }
    } else {
      await exportProjectAsPng();
    }
  }

  function normalizeTimelapseFps(value) {
    const parsed = Number(value);
    if (!Number.isFinite(parsed)) {
      return TIMELAPSE_DEFAULT_FPS;
    }
    return clamp(Math.round(parsed), TIMELAPSE_MIN_FPS, TIMELAPSE_MAX_FPS);
  }

  function createEmptyTimelapseTrack() {
    return {
      snapshots: [],
      warningShown: false,
      sampleStep: 1,
      lastCaptureToken: -1,
    };
  }

  function normalizeTimelapseCanvasId(value, fallback = '') {
    if (typeof value === 'string' && value.trim()) {
      return value.trim();
    }
    if (typeof fallback === 'string' && fallback.trim()) {
      return fallback.trim();
    }
    return getActiveProjectCanvasDocument()?.id || '';
  }

  function getTimelapseTrack(canvasId = '', { create = false } = {}) {
    const resolvedCanvasId = normalizeTimelapseCanvasId(canvasId);
    if (!resolvedCanvasId) {
      return null;
    }
    const existing = timelapseState.tracksByCanvasId[resolvedCanvasId];
    if (existing) {
      return existing;
    }
    if (!create) {
      return null;
    }
    const track = createEmptyTimelapseTrack();
    timelapseState.tracksByCanvasId[resolvedCanvasId] = track;
    return track;
  }

  function getActiveTimelapseTrack(options = {}) {
    return getTimelapseTrack(getActiveProjectCanvasDocument()?.id || '', options);
  }

  function getAllTimelapseTracks() {
    return timelapseState.tracksByCanvasId;
  }

  function getActiveTimelapseStepCount() {
    return getActiveTimelapseTrack()?.snapshots?.length || 0;
  }

  function getAllTimelapseStepCount() {
    return Object.values(getAllTimelapseTracks()).reduce((sum, track) => {
      return sum + (Array.isArray(track?.snapshots) ? track.snapshots.length : 0);
    }, 0);
  }

  function reconcileTimelapseTracksForSingleCanvas() {
    const activeCanvasId = getActiveProjectCanvasDocument()?.id || '';
    if (!activeCanvasId || getProjectCanvasCount() !== 1) {
      return false;
    }
    if (timelapseState.tracksByCanvasId[activeCanvasId]) {
      return false;
    }
    const entries = Object.entries(timelapseState.tracksByCanvasId);
    if (!entries.length) {
      return false;
    }
    let bestTrack = null;
    let bestCount = -1;
    entries.forEach(([, track]) => {
      const count = Array.isArray(track?.snapshots) ? track.snapshots.length : 0;
      if (count > bestCount) {
        bestCount = count;
        bestTrack = track;
      }
    });
    if (!bestTrack || bestCount <= 0) {
      return false;
    }
    timelapseState.tracksByCanvasId = {
      [activeCanvasId]: {
        snapshots: Array.isArray(bestTrack.snapshots) ? bestTrack.snapshots.slice() : [],
        warningShown: Boolean(bestTrack.warningShown),
        sampleStep: Math.max(1, Math.round(Number(bestTrack.sampleStep) || 1)),
        lastCaptureToken: Number.isFinite(Number(bestTrack.lastCaptureToken))
          ? Math.round(Number(bestTrack.lastCaptureToken))
          : -1,
      },
    };
    return true;
  }

  function pruneTimelapseTracksToExistingCanvases() {
    const validCanvasIds = new Set(
      getProjectCanvasDocuments()
        .map(canvas => (typeof canvas?.id === 'string' ? canvas.id : ''))
        .filter(Boolean)
    );
    Object.keys(timelapseState.tracksByCanvasId).forEach(canvasId => {
      if (!validCanvasIds.has(canvasId)) {
        delete timelapseState.tracksByCanvasId[canvasId];
      }
    });
    Array.from(timelapseQueuedCanvasIds).forEach(canvasId => {
      if (!validCanvasIds.has(canvasId)) {
        timelapseQueuedCanvasIds.delete(canvasId);
      }
    });
  }

  function createTimelapseFrameEntryFromCanvas(canvasDoc = getActiveProjectCanvasDocument()) {
    const width = Math.max(1, Number(canvasDoc?.width) || 1);
    const height = Math.max(1, Number(canvasDoc?.height) || 1);
    const frames = Array.isArray(canvasDoc?.frames) ? canvasDoc.frames : [];
    if (!frames.length) {
      return null;
    }
    const frameIndex = clamp(Math.round(Number(canvasDoc?.activeFrame) || 0), 0, frames.length - 1);
    const frame = frames[frameIndex];
    if (!frame) {
      return null;
    }
    const pixels = compositeFramePixels(frame, width, height, state.palette);
    return {
      width,
      height,
      pixels: compressUint8Array(pixels, { clamped: true }),
    };
  }

  function createTimelapseFrameEntryFromState() {
    return createTimelapseFrameEntryFromCanvas(getActiveProjectCanvasDocument());
  }

  function createTimelapseFrameEntryFromSnapshot(snapshot) {
    if (!snapshot || typeof snapshot !== 'object') {
      return null;
    }
    let resolved = snapshot;
    const sampleIndices = snapshot?.frames?.[0]?.layers?.[0]?.indices;
    if (!(sampleIndices instanceof Int16Array)) {
      try {
        resolved = decompressHistorySnapshot(snapshot);
      } catch (error) {
        return null;
      }
    }
    const width = Math.max(1, Number(resolved.width) || 1);
    const height = Math.max(1, Number(resolved.height) || 1);
    const frames = Array.isArray(resolved.frames) ? resolved.frames : [];
    if (!frames.length) {
      return null;
    }
    const frameIndex = clamp(Math.round(Number(resolved.activeFrame) || 0), 0, frames.length - 1);
    const frame = frames[frameIndex] || frames[0];
    if (!frame) {
      return null;
    }
    const palette = Array.isArray(resolved.palette) ? resolved.palette : state.palette;
    const pixels = compositeFramePixels(frame, width, height, palette);
    return {
      width,
      height,
      pixels: compressUint8Array(pixels, { clamped: true }),
    };
  }

  function thinTimelapseSnapshotsIfNeeded(track = getActiveTimelapseTrack()) {
    const snapshots = Array.isArray(track?.snapshots) ? track.snapshots : null;
    if (!Array.isArray(snapshots) || snapshots.length <= TIMELAPSE_MAX_STEPS) {
      return false;
    }
    for (let index = snapshots.length - 2; index >= 1; index -= 2) {
      snapshots.splice(index, 1);
    }
    track.sampleStep = Math.max(1, Math.round(Number(track.sampleStep) || 1) * 2);
    return true;
  }

  function areTimelapseFrameEntriesEqual(a, b) {
    const resolvedA = resolveTimelapseFrameEntry(a);
    const resolvedB = resolveTimelapseFrameEntry(b);
    if (!resolvedA || !resolvedB) {
      return false;
    }
    if (resolvedA.width !== resolvedB.width || resolvedA.height !== resolvedB.height) {
      return false;
    }
    if (resolvedA.pixels.length !== resolvedB.pixels.length) {
      return false;
    }
    for (let index = 0; index < resolvedA.pixels.length; index += 1) {
      if (resolvedA.pixels[index] !== resolvedB.pixels[index]) {
        return false;
      }
    }
    return true;
  }

  function captureTimelapseFrameFromState(canvasId = getActiveProjectCanvasDocument()?.id || '') {
    if (!timelapseState.enabled) {
      return false;
    }
    const resolvedCanvasId = normalizeTimelapseCanvasId(canvasId);
    const canvasDoc = getProjectCanvasDocumentById(resolvedCanvasId) || getActiveProjectCanvasDocument();
    const entry = createTimelapseFrameEntryFromCanvas(canvasDoc);
    if (!entry) {
      return false;
    }
    const track = getTimelapseTrack(resolvedCanvasId, { create: true });
    const lastEntry = Array.isArray(track.snapshots) && track.snapshots.length
      ? track.snapshots[track.snapshots.length - 1]
      : null;
    if (lastEntry && areTimelapseFrameEntriesEqual(lastEntry, entry)) {
      track.lastCaptureToken = unsavedChangeToken;
      if (getActiveProjectCanvasDocument()?.id === resolvedCanvasId) {
        syncTimelapseControls();
      }
      return false;
    }
    track.snapshots.push(entry);
    track.lastCaptureToken = unsavedChangeToken;
    const thinned = thinTimelapseSnapshotsIfNeeded(track);
    if (thinned && !track.warningShown) {
      track.warningShown = true;
      updateAutosaveStatus('タイムラプス記録が増えたため自動で間引きしました', 'warn');
    }
    if (getActiveProjectCanvasDocument()?.id === resolvedCanvasId) {
      syncTimelapseControls();
    }
    updateMemoryStatus();
    return true;
  }

  function ensureTimelapseStartCapture(canvasId = getActiveProjectCanvasDocument()?.id || '') {
    if (!timelapseState.enabled) {
      return false;
    }
    const resolvedCanvasId = normalizeTimelapseCanvasId(canvasId);
    if (!resolvedCanvasId) {
      return false;
    }
    const track = getTimelapseTrack(resolvedCanvasId);
    if (track && Array.isArray(track.snapshots) && track.snapshots.length > 0) {
      return false;
    }
    return captureTimelapseFrameFromState(resolvedCanvasId);
  }

  function flushPendingTimelapseCapture({ force = false } = {}) {
    const queuedCanvasIds = Array.from(timelapseQueuedCanvasIds);
    if (timelapseCaptureTimer !== null) {
      window.clearTimeout(timelapseCaptureTimer);
      timelapseCaptureTimer = null;
    }
    if (!queuedCanvasIds.length && !force) {
      return false;
    }
    timelapseQueuedCanvasIds.clear();
    if (!timelapseState.enabled) {
      return false;
    }
    let captured = false;
    queuedCanvasIds.forEach(canvasId => {
      captured = captureTimelapseFrameFromState(canvasId) || captured;
    });
    return captured;
  }

  function scheduleTimelapseCaptureFromState({ immediate = false, canvasId = getActiveProjectCanvasDocument()?.id || '' } = {}) {
    if (!timelapseState.enabled) {
      return;
    }
    const resolvedCanvasId = normalizeTimelapseCanvasId(canvasId);
    if (!resolvedCanvasId) {
      return;
    }
    timelapseQueuedCanvasIds.add(resolvedCanvasId);
    if (immediate) {
      flushPendingTimelapseCapture();
      return;
    }
    if (timelapseCaptureTimer !== null) {
      return;
    }
    timelapseCaptureTimer = window.setTimeout(() => {
      timelapseCaptureTimer = null;
      flushPendingTimelapseCapture();
    }, TIMELAPSE_CAPTURE_DEBOUNCE_MS);
  }

  function syncTimelapseControls() {
    const track = getActiveTimelapseTrack();
    const stepCount = Array.isArray(track?.snapshots) ? track.snapshots.length : 0;
    const fps = normalizeTimelapseFps(timelapseState.fps);
    const sampleStep = Math.max(1, Math.round(Number(track?.sampleStep) || 1));
    const sampleInfo = sampleStep > 1
      ? localizeText(` / 間引きx${sampleStep}`, ` / thinning x${sampleStep}`)
      : '';
    timelapseState.fps = fps;

    if (dom.controls.toggleTimelapse instanceof HTMLInputElement) {
      dom.controls.toggleTimelapse.checked = Boolean(timelapseState.enabled);
    }
    if (dom.controls.timelapseClear instanceof HTMLButtonElement) {
      dom.controls.timelapseClear.disabled = stepCount <= 0;
    }
    if (dom.controls.timelapseFps instanceof HTMLInputElement) {
      dom.controls.timelapseFps.value = String(fps);
    }
    if (dom.controls.timelapseStatus) {
      const status = timelapseState.enabled ? 'ON' : 'OFF';
      dom.controls.timelapseStatus.textContent = localizeText(
        `タイムラプス: ${status} (${stepCount}ステップ / ${fps}fps${sampleInfo})`,
        `Timelapse: ${status} (${stepCount} steps / ${fps}fps${sampleInfo})`
      );
    }
  }

  function clearTimelapseRecording({ silent = false, scope = 'active' } = {}) {
    if (timelapseCaptureTimer !== null) {
      window.clearTimeout(timelapseCaptureTimer);
      timelapseCaptureTimer = null;
    }
    if (scope === 'all') {
      timelapseQueuedCanvasIds.clear();
      timelapseState.tracksByCanvasId = Object.create(null);
    } else {
      const activeCanvasId = normalizeTimelapseCanvasId(getActiveProjectCanvasDocument()?.id || '');
      timelapseQueuedCanvasIds.delete(activeCanvasId);
      const track = getTimelapseTrack(activeCanvasId);
      if (track) {
        track.snapshots.length = 0;
        track.warningShown = false;
        track.sampleStep = 1;
        track.lastCaptureToken = -1;
      }
    }
    syncTimelapseControls();
    if (!silent) {
      updateAutosaveStatus(
        scope === 'all'
          ? 'タイムラプス記録をすべてクリアしました'
          : 'このキャンバスのタイムラプス記録をクリアしました',
        'info'
      );
    }
    updateMemoryStatus();
  }

  function setTimelapseEnabled(enabled, { persist = true } = {}) {
    const next = Boolean(enabled);
    if (timelapseState.enabled === next) {
      syncTimelapseControls();
      return;
    }
    timelapseState.enabled = next;
    if (next) {
      scheduleTimelapseCaptureFromState({ immediate: true });
    } else if (timelapseCaptureTimer !== null) {
      window.clearTimeout(timelapseCaptureTimer);
      timelapseCaptureTimer = null;
      timelapseQueuedCanvasIds.clear();
    }
    syncTimelapseControls();
    updateAutosaveStatus(
      next ? 'タイムラプス記録をONにしました' : 'タイムラプス記録をOFFにしました',
      'info'
    );
    if (persist) {
      scheduleSessionPersist({ includeSnapshots: false });
    }
  }

  function resolveTimelapseFrameEntry(entry) {
    if (!entry || typeof entry !== 'object') {
      return null;
    }
    const width = Math.max(1, Number(entry.width) || 1);
    const height = Math.max(1, Number(entry.height) || 1);
    let pixels;
    try {
      pixels = decodeUint8Data(entry.pixels, { clamped: true });
    } catch (error) {
      return null;
    }
    const expectedLength = width * height * 4;
    if (!pixels || pixels.length !== expectedLength) {
      return null;
    }
    return {
      width,
      height,
      pixels: pixels instanceof Uint8ClampedArray ? pixels : new Uint8ClampedArray(pixels),
    };
  }

  function buildTimelapseExportEntries() {
    flushPendingTimelapseCapture();
    const activeCanvasId = normalizeTimelapseCanvasId(getActiveProjectCanvasDocument()?.id || '');
    const track = getTimelapseTrack(activeCanvasId);
    const snapshots = Array.isArray(track?.snapshots) ? track.snapshots.slice() : [];
    if (timelapseState.enabled) {
      const current = createTimelapseFrameEntryFromState();
      if (current && (!snapshots.length || !areTimelapseFrameEntriesEqual(snapshots[snapshots.length - 1], current))) {
        snapshots.push(current);
      }
    }
    return snapshots;
  }

  async function exportTimelapseGif() {
    if (!ensureCurrentClientCanExportProject({ announce: true, format: 'timelapse' })) {
      return;
    }
    if (getActiveTimelapseStepCount() <= 0) {
      updateAutosaveStatus('タイムラプス記録がありません。設定でONにして描画してください。', 'warn');
      return;
    }
    const snapshots = buildTimelapseExportEntries();
    if (!snapshots.length) {
      updateAutosaveStatus('タイムラプス記録がありません', 'warn');
      return;
    }

    try {
      updateAutosaveStatus('タイムラプスGIFを書き出し中…', 'info');
      const candidates = getExportScaleCandidates();
      const selectedScale = applyExportScaleConstraints(candidates);
      syncExportScaleInputs();
      const targetWidth = Math.max(1, Number(state.width) || 1);
      const targetHeight = Math.max(1, Number(state.height) || 1);
      const framePixels = [];
      let skippedSizeMismatch = 0;
      let skippedInvalid = 0;

      for (let i = 0; i < snapshots.length; i += 1) {
        const resolved = resolveTimelapseFrameEntry(snapshots[i]);
        if (!resolved) {
          skippedInvalid += 1;
          continue;
        }
        const width = resolved.width;
        const height = resolved.height;
        if (width !== targetWidth || height !== targetHeight) {
          skippedSizeMismatch += 1;
          continue;
        }
        framePixels.push(resolved.pixels);
      }

      if (!framePixels.length) {
        updateAutosaveStatus('タイムラプスGIFを書き出せませんでした', 'error');
        return;
      }

      const fps = normalizeTimelapseFps(timelapseState.fps);
      timelapseState.fps = fps;
      const frameDuration = clamp(Math.round(1000 / fps), 16, 2000);
      const frameDurations = new Array(framePixels.length).fill(frameDuration);
      const scaledSet = scaleFrameSetNearestNeighbor(framePixels, targetWidth, targetHeight, selectedScale);
      const gifBytes = buildGifFromPixels(
        scaledSet.framePixels,
        frameDurations,
        scaledSet.width,
        scaledSet.height
      );
      const tasks = [{
        blob: new Blob([gifBytes], { type: 'image/gif' }),
        filename: createExportFileName('gif', selectedScale > 1 ? `timelapse_x${selectedScale}` : 'timelapse'),
        shareText: `タイムラプスGIFを書き出しました (${framePixels.length}ステップ${selectedScale > 1 ? ` / ×${selectedScale}` : ''})`,
      }];
      const result = await deliverExportTasks(tasks, {
        mimeType: 'image/gif',
        fileExtensions: ['.gif'],
        shareTitle: state.documentName || 'PiXiEEDraw',
        shareText: 'タイムラプスGIFを書き出しました',
      });

      const detailParts = [`${framePixels.length}ステップ`];
      if (selectedScale > 1) {
        detailParts.push(`×${selectedScale}`);
      }
      const skipped = skippedSizeMismatch + skippedInvalid;
      if (skipped > 0) {
        detailParts.push(`除外 ${skipped}`);
      }
      const detail = detailParts.join(' / ');
      if (result.exportedCount === result.total) {
        updateAutosaveStatus(`タイムラプスGIFを書き出しました (${detail})`, 'success');
      } else if (result.wasCancelled) {
        updateAutosaveStatus('タイムラプスGIFの書き出しをキャンセルしました', 'warn');
      } else if (result.exportedCount > 0 && result.hadFailure) {
        updateAutosaveStatus('タイムラプスGIFを書き出しましたが一部失敗しました', 'warn');
      } else {
        updateAutosaveStatus('タイムラプスGIFの書き出しに失敗しました', 'error');
      }
      if (result.exportedCount > 0) {
        markDocumentDurablySaved();
        if (result.exportedCount === result.total && !result.wasCancelled && !result.hadFailure) {
          const companionResult = await maybeSaveProjectCompanionAfterExport('timelapse', {
            exportedCount: result.exportedCount,
            wasCancelled: result.wasCancelled,
          });
          announceProjectCompanionSaveResult('timelapse', companionResult);
        }
        showLoginPromptAfterExport();
      }
      syncTimelapseControls();
    } catch (error) {
      console.error('Timelapse export failed', error);
      updateAutosaveStatus('タイムラプスGIFの書き出しに失敗しました', 'error');
    }
  }

  function normalizeFpsValue(value) {
    return clamp(Math.round(Number(value) || 0), 1, 60);
  }

  function getDurationFromFps(fps) {
    if (!Number.isFinite(fps) || fps <= 0) {
      return 1000 / 12;
    }
    return 1000 / fps;
  }

  function updateAnimationFpsDisplay(fps, durationMs) {
    if (dom.controls.animationFps) {
      dom.controls.animationFps.value = String(fps);
    }
    if (dom.controls.animationFpsMs) {
      const rounded = Math.max(1, Math.round(Number(durationMs) || 0));
      dom.controls.animationFpsMs.textContent = `${rounded}ms`;
    }
  }

  function syncAnimationFpsDisplayFromState() {
    const frame = getActiveFrame();
    const duration = frame && Number.isFinite(frame.duration) && frame.duration > 0
      ? frame.duration
      : 1000 / 12;
    const fps = normalizeFpsValue(Math.round(1000 / duration));
    updateAnimationFpsDisplay(fps, duration);
  }

  function applyFpsToAllFrames(fpsValue) {
    if (!canCurrentClientEditProjectStructure()) {
      setMultiStatus(localizeText('参加/視聴モードではfps設定はマスターのみ変更できます', 'In participant/viewer mode, only the master can change FPS'), 'warn');
      return;
    }
    const frames = state.frames;
    if (!Array.isArray(frames) || !frames.length) {
      return;
    }
    const clampedFps = normalizeFpsValue(fpsValue);
    const nextDuration = getDurationFromFps(clampedFps);
    const hasChange = frames.some(frame => Math.abs(frame.duration - nextDuration) > 0.001);
    if (!hasChange) {
      updateAnimationFpsDisplay(clampedFps, nextDuration);
      return;
    }
    beginHistory('setAllFrameFps');
    frames.forEach(frame => {
      frame.duration = nextDuration;
    });
    markHistoryDirty();
    commitHistory();
    scheduleSessionPersist();
    renderTimelineMatrix();
    updateAnimationFpsDisplay(clampedFps, nextDuration);
  }

  function setActiveFrameIndex(nextIndex, {
    wrap = false,
    persist = true,
    render = true,
    syncUi = true,
  } = {}) {
    const frames = state.frames;
    if (!Array.isArray(frames) || !frames.length) {
      return null;
    }
    const length = frames.length;
    const normalizedIndex = wrap
      ? ((Math.round(nextIndex) % length) + length) % length
      : clamp(Math.round(nextIndex), 0, length - 1);
    const previousIndex = state.activeFrame;
    state.activeFrame = normalizedIndex;
    getProjectCanvasDocuments().forEach(canvasDoc => {
      if (!canvasDoc || !Array.isArray(canvasDoc.frames) || !canvasDoc.frames.length) {
        return;
      }
      canvasDoc.activeFrame = clamp(normalizedIndex, 0, canvasDoc.frames.length - 1);
      const targetFrame = canvasDoc.frames[canvasDoc.activeFrame];
      if (targetFrame && Array.isArray(targetFrame.layers) && !targetFrame.layers.some(layer => layer?.id === canvasDoc.activeLayer)) {
        canvasDoc.activeLayer = targetFrame.layers[targetFrame.layers.length - 1]?.id || targetFrame.layers[0]?.id || canvasDoc.activeLayer;
      }
    });
    const frame = frames[normalizedIndex];
    if (frame && (!frame.layers.some(layer => layer.id === state.activeLayer) || !state.activeLayer)) {
      const lastLayer = frame.layers[frame.layers.length - 1];
      if (lastLayer) {
        state.activeLayer = lastLayer.id;
      }
    }
    if (isVoxelExtensionModeEnabled()) {
      const frameOrientation = getVoxelPreviewOrientationForFrameIndex(
        normalizedIndex,
        voxelExtensionState.previewYawDeg,
        voxelExtensionState.previewPitchDeg
      );
      voxelExtensionState = normalizeVoxelExtensionState({
        ...voxelExtensionState,
        previewYawDeg: frameOrientation.yawDeg,
        previewPitchDeg: frameOrientation.pitchDeg,
      }, VOXEL_EXTENSION_DEFAULT_STATE);
      syncVoxelExtensionPreviewFromSource({ updateViewport: false });
    }
    if (isMultiAssignedCellRestrictedEditorMode()) {
      enforceGuestAssignedLayerSelection({ announce: false });
    }
    if (persist) {
      scheduleSessionPersist();
    }
    if (render) {
      if (previousIndex !== normalizedIndex) {
        if (isVoxelExtensionModeEnabled()) {
          syncVoxelExtensionPreviewFromSource({ updateViewport: false });
        }
        renderFrameList();
        renderLayerList();
        requestRender();
        requestOverlayRender();
      } else {
        syncAnimationFpsDisplayFromState();
        syncActiveFrameSettingsUI();
      }
    }
    if (syncUi) {
      updatePixfindModeUI();
    }
    return frame;
  }

  function stepActiveFrame(offset, options = {}) {
    const frames = state.frames;
    if (!Array.isArray(frames) || !frames.length) {
      return;
    }
    const wrap = options.wrap !== false;
    const persist = options.persist !== false;
    const render = options.render !== false;
    const syncUi = options.syncUi !== false;
    const nextIndex = state.activeFrame + Number(offset || 0);
    setActiveFrameIndex(nextIndex, { wrap, persist, render, syncUi });
  }

  function setActiveLayerTrackIndex(nextIndex, {
    persist = true,
    render = true,
    syncUi = true,
  } = {}) {
    const frame = getActiveFrame();
    if (!frame || !Array.isArray(frame.layers) || !frame.layers.length) {
      return null;
    }
    if (isMultiAssignedCellRestrictedEditorMode()) {
      enforceGuestAssignedLayerSelection({ announce: false });
      return getActiveLayer();
    }
    const normalizedIndex = clamp(Math.round(Number(nextIndex) || 0), 0, frame.layers.length - 1);
    const nextLayer = frame.layers[normalizedIndex];
    if (!nextLayer) {
      return null;
    }
    const previousLayerId = state.activeLayer;
    state.activeLayer = nextLayer.id;
    const activeCanvasDoc = getActiveProjectCanvasDocument();
    if (activeCanvasDoc) {
      activeCanvasDoc.activeLayer = nextLayer.id;
    }
    if (persist) {
      scheduleSessionPersist();
    }
    if (render) {
      if (previousLayerId !== nextLayer.id) {
        renderFrameList();
        renderLayerList();
        requestRender();
        requestOverlayRender();
      } else {
        syncActiveLayerSettingsUI();
      }
    }
    if (syncUi) {
      updatePixfindModeUI();
    }
    return nextLayer;
  }

  function stepActiveLayerTrack(offset, options = {}) {
    const frame = getActiveFrame();
    if (!frame || !Array.isArray(frame.layers) || !frame.layers.length) {
      return null;
    }
    const currentIndex = getActiveLayerIndex();
    const baseIndex = currentIndex >= 0 ? currentIndex : frame.layers.length - 1;
    const nextIndex = baseIndex + Number(offset || 0);
    return setActiveLayerTrackIndex(nextIndex, options);
  }

  function addOrDuplicateFrameAfterActive({ duplicate = false } = {}) {
    if (state.playback.isPlaying) {
      return false;
    }
    if (!canCurrentClientEditProjectStructure()) {
      setMultiStatus(
        localizeText(
          duplicate
            ? '参加/視聴モードではフレーム複製はマスターのみ操作できます'
            : '参加/視聴モードではフレーム追加はマスターのみ操作できます',
          duplicate
            ? 'In participant/viewer mode, only the master can duplicate frames'
            : 'In participant/viewer mode, only the master can add frames'
        ),
        'warn'
      );
      return false;
    }
    const baseFrame = getActiveFrame();
    if (!baseFrame) {
      return false;
    }
    clearTimelineSelection();
    beginHistory(duplicate ? 'duplicateFrame' : 'addFrame');
    const nextFrameNumber = clamp(state.activeFrame + 2, 1, Number.MAX_SAFE_INTEGER);
    if (isVoxelExtensionModeEnabled()) {
      getProjectCanvasDocuments().forEach(canvasDoc => {
        if (!canvasDoc || !Array.isArray(canvasDoc.frames) || !canvasDoc.frames.length) {
          return;
        }
        const sourceFrame = canvasDoc.frames[clamp(state.activeFrame, 0, canvasDoc.frames.length - 1)] || canvasDoc.frames[canvasDoc.frames.length - 1];
        if (!sourceFrame || !Array.isArray(sourceFrame.layers)) {
          return;
        }
        const newFrame = createFrame(
          getDefaultFrameName(nextFrameNumber),
          sourceFrame.layers,
          canvasDoc.width || state.width,
          canvasDoc.height || state.height,
          { copyPixels: duplicate }
        );
        if (Number.isFinite(sourceFrame.duration) && sourceFrame.duration > 0) {
          newFrame.duration = sourceFrame.duration;
        }
        newFrame.voxelPreviewYawDeg = normalizeVoxelPreviewYawDegrees(sourceFrame?.voxelPreviewYawDeg);
        newFrame.voxelPreviewPitchDeg = normalizeVoxelPreviewPitchDegrees(sourceFrame?.voxelPreviewPitchDeg);
        if (duplicate) {
          newFrame.name = getDefaultFrameName(nextFrameNumber);
        }
        canvasDoc.frames.splice(clamp(state.activeFrame + 1, 0, Number.MAX_SAFE_INTEGER), 0, newFrame);
        canvasDoc.activeFrame = clamp(state.activeFrame + 1, 0, canvasDoc.frames.length - 1);
        canvasDoc.activeLayer = newFrame.layers[newFrame.layers.length - 1]?.id || canvasDoc.activeLayer;
      });
    } else {
      const sourceLayers = baseFrame.layers;
      const newFrame = createFrame(
        getDefaultFrameName(nextFrameNumber),
        sourceLayers,
        state.width,
        state.height,
        { copyPixels: duplicate }
      );
      if (Number.isFinite(baseFrame.duration) && baseFrame.duration > 0) {
        newFrame.duration = baseFrame.duration;
      }
      newFrame.voxelPreviewYawDeg = normalizeVoxelPreviewYawDegrees(baseFrame?.voxelPreviewYawDeg);
      newFrame.voxelPreviewPitchDeg = normalizeVoxelPreviewPitchDegrees(baseFrame?.voxelPreviewPitchDeg);
      if (duplicate) {
        newFrame.name = getDefaultFrameName(nextFrameNumber);
      }
      state.frames.splice(state.activeFrame + 1, 0, newFrame);
    }
    clearPendingMultiAssignmentMoveRequests();
    state.activeFrame += 1;
    const nextActiveFrame = getActiveFrame();
    state.activeLayer = nextActiveFrame?.layers?.[nextActiveFrame.layers.length - 1]?.id || state.activeLayer;
    markHistoryDirty();
    scheduleSessionPersist();
    renderFrameList();
    renderLayerList();
    requestRender();
    requestOverlayRender();
    commitHistory();
    updateAutosaveStatus(
      localizeText(
        duplicate ? 'フレームを複製しました' : 'フレームを追加しました',
        duplicate ? 'Frame duplicated' : 'Frame added'
      ),
      'success'
    );
    return true;
  }

  function togglePlaybackFromShortcut() {
    if (state.playback.isPlaying) {
      stopPlayback();
      return true;
    }
    startPlayback();
    return Boolean(state.playback.isPlaying);
  }

  function openNewProjectDialog({ dismissStartup = false } = {}) {
    if (!ensureCurrentClientCanReplaceActiveProject()) {
      return;
    }
    const config = dom.newProject;
    if (!config) {
      void promptNewProjectFallback();
      return;
    }
    const dialog = config.dialog;
    if (dialog && typeof dialog.showModal === 'function') {
      try {
        if (config.nameInput) {
          const currentName = state.documentName || DEFAULT_DOCUMENT_NAME;
          config.nameInput.value = extractDocumentBaseName(currentName);
        }
        if (config.widthInput) {
          config.widthInput.value = String(state.width);
        }
        if (config.heightInput) {
          config.heightInput.value = String(state.height);
        }
        if (config.palettePreset) {
          const normalizedPreset = normalizeNewProjectPalettePreset(
            newProjectPalettePresetId,
            NEW_PROJECT_PALETTE_PRESET_DEFAULT
          );
          renderNewProjectPalettePresetOptions(normalizedPreset);
          config.palettePreset.value = normalizedPreset;
          renderNewProjectPalettePresetPicker(normalizedPreset);
          setNewProjectPalettePresetPickerOpen(false);
        }
        dialog.showModal();
        if (dismissStartup) {
          hideStartupScreen();
        }
        window.requestAnimationFrame(() => {
          queueNewProjectAdRender();
          config.nameInput?.focus();
          config.nameInput?.select?.();
        });
        return;
      } catch (error) {
        console.warn('Failed to open new project dialog', error);
      }
    }
    if (dismissStartup) {
      hideStartupScreen();
    }
    void promptNewProjectFallback();
  }

  function queueNewProjectAdRender() {
    if (window.__PIXIEED_ADS_DISABLED__ || window.pixieedAdFree?.state?.isActive) {
      return;
    }
    const dialog = dom.newProject?.dialog;
    const adSlot = dom.newProject?.adSlot;
    if (!(dialog instanceof HTMLDialogElement) || !dialog.open || !(adSlot instanceof HTMLElement)) {
      return;
    }
    if (newProjectAdRequested) {
      return;
    }
    if (adSlot.dataset.loaded === '1' || adSlot.getAttribute('data-adsbygoogle-status') === 'done') {
      newProjectAdRequested = true;
      return;
    }
    if (!adSlot.classList.contains('adsbygoogle')) {
      adSlot.classList.add('adsbygoogle');
    }

    const getWidth = () => {
      try {
        const rect = adSlot.getBoundingClientRect();
        return (rect && rect.width) || adSlot.clientWidth || adSlot.offsetWidth || 0;
      } catch (error) {
        return adSlot.clientWidth || adSlot.offsetWidth || 0;
      }
    };

    let attempts = 0;
    const MAX_ATTEMPTS = 24;
    const renderWhenReady = () => {
      if (!(dialog instanceof HTMLDialogElement) || !dialog.open) {
        newProjectAdRequested = false;
        return;
      }
      const width = getWidth();
      if (width <= 0) {
        attempts += 1;
        if (attempts < MAX_ATTEMPTS) {
          window.requestAnimationFrame(renderWhenReady);
          return;
        }
        newProjectAdRequested = false;
        return;
      }
      newProjectAdRequested = true;
      try {
        (window.adsbygoogle = window.adsbygoogle || []).push({});
        adSlot.dataset.loaded = '1';
      } catch (error) {
        newProjectAdRequested = false;
      }
    };

    window.requestAnimationFrame(renderWhenReady);
  }

  function setupExportDialog() {
    const config = dom.exportDialog;
    if (!config) {
      return;
    }
    const dialog = config.dialog;
    const supportsDialog = dialog && typeof dialog.showModal === 'function';
    const bind = (element, handler) => {
      if (element) {
        element.addEventListener('click', handler);
      }
    };
    bind(config.confirm, () => {
      const mode = normalizeExportFormat(config.format?.value || 'png');
      if (!ensureCurrentClientCanExportProject({ announce: true, format: mode })) {
        updateExportFormatAvailability();
        return;
      }
      if (mode === 'contest') {
        updateAutosaveStatus('コンテスト投稿は現在停止中です', 'warn');
        closeExportDialog();
        return;
      }
      closeExportDialog();
      queueExportWithInterstitial(() => performExportByMode(mode));
    });
    bind(config.cancel, () => {
      closeExportDialog();
    });
    if (supportsDialog && dialog) {
      dialog.addEventListener('cancel', event => {
        event.preventDefault();
        closeExportDialog();
      });
    } else if (dialog) {
      dialog.hidden = true;
    }
    if (!supportsDialog && config.adContainer) {
      config.adContainer.hidden = true;
    }
    if (config.format && config.format.dataset.bound !== 'true') {
      config.format.dataset.bound = 'true';
      config.format.addEventListener('change', () => {
        refreshExportScaleControls();
        updateExportFormatAvailability();
        updateExportOriginalToggleUI();
      });
    }
    if (config.includeOriginalToggle instanceof HTMLInputElement && config.includeOriginalToggle.dataset.bound !== 'true') {
      config.includeOriginalToggle.dataset.bound = 'true';
      config.includeOriginalToggle.checked = exportIncludeOriginalSize;
      config.includeOriginalToggle.addEventListener('change', event => {
        exportIncludeOriginalSize = Boolean(event.target.checked);
        scheduleSessionPersist({ includeSnapshots: false });
        updateExportOriginalToggleUI();
      });
    }
    if (config.saveProjectCompanionToggle instanceof HTMLInputElement
      && config.saveProjectCompanionToggle.dataset.bound !== 'true') {
      config.saveProjectCompanionToggle.dataset.bound = 'true';
      config.saveProjectCompanionToggle.checked = exportSaveProjectCompanion;
      config.saveProjectCompanionToggle.addEventListener('change', event => {
        exportSaveProjectCompanion = Boolean(event.target.checked);
        scheduleSessionPersist({ includeSnapshots: false });
        updateExportProjectCompanionToggleUI();
      });
    }
    if (config.contestPostToggle instanceof HTMLInputElement
      && config.contestPostToggle.dataset.bound !== 'true') {
      config.contestPostToggle.dataset.bound = 'true';
      config.contestPostToggle.checked = exportContestPostAfterSave;
      config.contestPostToggle.addEventListener('change', event => {
        exportContestPostAfterSave = Boolean(event.target.checked);
        scheduleSessionPersist({ includeSnapshots: false });
        updateExportContestPostToggleUI();
      });
    }

    const slider = config.scaleSlider;
    if (slider && slider.dataset.bound !== 'true') {
      slider.dataset.bound = 'true';
      slider.addEventListener('input', event => {
        exportScaleUserOverride = true;
        setExportScale(event.target.value);
      });
    }

    const scaleInput = config.scaleInput;
    if (scaleInput && scaleInput.dataset.bound !== 'true') {
      scaleInput.dataset.bound = 'true';
      scaleInput.addEventListener('change', event => {
        exportScaleUserOverride = true;
        setExportScale(event.target.value);
      });
    }

    const widthInput = config.pixelWidthInput;
    if (widthInput && widthInput.dataset.bound !== 'true') {
      widthInput.dataset.bound = 'true';
      widthInput.addEventListener('change', event => {
        exportScaleUserOverride = true;
        if (!exportSheetInfo) {
          syncExportScaleInputs();
          return;
        }
        const desiredWidth = Math.round(Number(event.target.value));
        if (!Number.isFinite(desiredWidth) || desiredWidth <= 0) {
          syncExportScaleInputs();
          return;
        }
        const baseWidth = Math.max(1, exportSheetInfo.sheetWidth);
        const targetScale = clamp(Math.round(desiredWidth / baseWidth), 1, exportMaxScale || 1);
        setExportScale(targetScale);
      });
    }

    const heightInput = config.pixelHeightInput;
    if (heightInput && heightInput.dataset.bound !== 'true') {
      heightInput.dataset.bound = 'true';
      heightInput.addEventListener('change', event => {
        exportScaleUserOverride = true;
        if (!exportSheetInfo) {
          syncExportScaleInputs();
          return;
        }
        const desiredHeight = Math.round(Number(event.target.value));
        if (!Number.isFinite(desiredHeight) || desiredHeight <= 0) {
          syncExportScaleInputs();
          return;
        }
        const baseHeight = Math.max(1, exportSheetInfo.sheetHeight);
        const targetScale = clamp(Math.round(desiredHeight / baseHeight), 1, exportMaxScale || 1);
        setExportScale(targetScale);
      });
    }

    const gridWidthInput = config.gridWidthInput;
    if (gridWidthInput instanceof HTMLInputElement && gridWidthInput.dataset.bound !== 'true') {
      gridWidthInput.dataset.bound = 'true';
      gridWidthInput.addEventListener('change', event => {
        exportGridTileWidth = normalizeExportGridTileSize(event.target.value, exportGridTileWidth);
        syncExportGridInputs();
        scheduleSessionPersist({ includeSnapshots: false });
      });
    }

    const gridHeightInput = config.gridHeightInput;
    if (gridHeightInput instanceof HTMLInputElement && gridHeightInput.dataset.bound !== 'true') {
      gridHeightInput.dataset.bound = 'true';
      gridHeightInput.addEventListener('change', event => {
        exportGridTileHeight = normalizeExportGridTileSize(event.target.value, exportGridTileHeight);
        syncExportGridInputs();
        scheduleSessionPersist({ includeSnapshots: false });
      });
    }

    syncExportGridInputs();
    updateExportFormatAvailability();
    updateExportOriginalToggleUI();
  }

