    leftUnifiedSplitSizing.pointerId = null;
    leftUnifiedSplitSizing.captureTarget = null;
    leftUnifiedSplitSizing.startClientY = 0;
    leftUnifiedSplitSizing.startToolsHeight = 0;
    leftUnifiedSplitSizing.startColorHeight = 0;
