    if (railSizing.pointerId !== null && event.pointerId !== railSizing.pointerId) {
      return;
    }
    const deltaX = (Number(event.clientX) || 0) - railSizing.startClientX;
    if (!railSizing.moved) {
      if (Math.abs(deltaX) < RAIL_RESIZE_DRAG_THRESHOLD) {
        return;
      }
      railSizing.moved = true;
    }
