        const dx = centroid.x - baselineCentroid.x;
        const dy = centroid.y - baselineCentroid.y;
        const panDistance = Math.hypot(dx, dy);
        const panGestureActive = panDistance >= TOUCH_PAN_DEADZONE_PX;
